using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap the JSONPlaceholder REST API.
/// Uses constructor injection for HttpClient and ILogger.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Get a post by its numeric ID from the API.")]
    public async Task<string> GetPost(
        [Description("The numeric ID of the post (1-100)")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {Id}", id);
        var post = await httpClient.GetFromJsonAsync<Post>(
            $"posts/{id}", cancellationToken);
        return $"Title: {post?.Title}\n\n{post?.Body}";
    }

    [McpServerTool, Description("List all posts by a specific user ID.")]
    public async Task<string> GetPostsByUser(
        [Description("The user ID to filter posts by (1-10)")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching posts for user {UserId}", userId);
        var posts = await httpClient.GetFromJsonAsync<Post[]>(
            $"posts?userId={userId}", cancellationToken);
        if (posts is null or { Length: 0 })
            return "No posts found for that user.";

        return string.Join("\n\n", posts.Select(p => $"[{p.Id}] {p.Title}"));
    }

    [McpServerTool, Description("Search for users by name (partial match).")]
    public async Task<string> SearchUsers(
        [Description("Name or partial name to search for")] string name,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching users by name: {Name}", name);
        var users = await httpClient.GetFromJsonAsync<User[]>(
            "users", cancellationToken);
        var matches = users?
            .Where(u => u.Name.Contains(name, StringComparison.OrdinalIgnoreCase))
            .ToArray();

        if (matches is null or { Length: 0 })
            return "No matching users found.";

        return string.Join("\n", matches.Select(u => $"{u.Name} ({u.Email})"));
    }
}

public record Post(
    [property: JsonPropertyName("id")] int Id,
    [property: JsonPropertyName("userId")] int UserId,
    [property: JsonPropertyName("title")] string Title,
    [property: JsonPropertyName("body")] string Body);

public record User(
    [property: JsonPropertyName("id")] int Id,
    [property: JsonPropertyName("name")] string Name,
    [property: JsonPropertyName("email")] string Email);

